sql:
SELECT DISTINCT nodes.network_id
FROM nodes
WHERE nodes.node_type = 'community';

external_knowledge:
- 'ongoing cycles' refers to iteration IDs in active states;
- 'functional networks' refers to networks in active status;
- 'active components' refer to nodes with an active status;

sql:
SELECT source_node_id, COUNT(edge_id) AS num_edges
FROM edges
GROUP BY source_node_id;

SELECT AVG(total_iterations) AS average_iterations
FROM (
    SELECT network_id, COUNT(*) AS total_iterations
    FROM iterations
    GROUP BY network_id
) AS network_iteration_counts;

SELECT COUNT(*) 
FROM node_attributes 
WHERE attribute_name = 'age';

SELECT SUM(attribute_value) AS total_weight_less_than_0_5
FROM edge_attributes
WHERE attribute_name = 'weight' AND attribute_value < 0.5;
